mapper.select:
SELECT * FROM service_task
WHERE 1 = 1

    AND workflow_code = #{workflowCode}


    AND current_stage_code = #{stageCode}


    AND customer_id = #{customerId}


    AND level = #{level}


    AND status = #{status}

ORDER BY created_at DESC

mapper.update:
UPDATE service_task
SET status     = #{status},
    updated_at = #{updatedAt}
WHERE id = #{id}

UPDATE service_task
SET status      = 'Processing',
    assigned_to = #{assignedTo},
    updated_at  = #{updatedAt}
WHERE id = #{id}
